.darma-loader-uiverse-prism-cross-scanner { display: inline-flex; align-items: center; justify-content: center; position: relative; }
.darma-loader-uiverse-prism-cross-scanner__loading {
  display: flex;
  justify-content: center;
  align-items: center;
}

.darma-loader-uiverse-prism-cross-scanner__loading-wide {
width: 150px;
height: 150px;
display: flex;
justify-content: center;
align-items: center;
position: relative;
}

.darma-loader-uiverse-prism-cross-scanner__color {
background-color: var(--loader-color, #4285f4); /* Google Blue */
}

.darma-loader-uiverse-prism-cross-scanner__l1 {
width: 15px;
height: 65px;
position: absolute;
animation: darma-loader-uiverse-prism-cross-scanner-move-h 1.2s infinite cubic-bezier(0.65, 0.05, 0.36, 1);
background-color: var(--loader-secondary-color, #f4b400); /* Google Yellow */
}

.darma-loader-uiverse-prism-cross-scanner__l2 {
width: 15px;
height: 60px;
position: absolute;
transform: rotate(90deg);
animation: darma-loader-uiverse-prism-cross-scanner-move-v 1.2s infinite cubic-bezier(0.65, 0.05, 0.36, 1);
background-color: #db4437; /* Google Red */
}

@keyframes darma-loader-uiverse-prism-cross-scanner-move-h {
0% {
top: 0;
opacity: 0;
}
25% {
opacity: 1;
}
50% {
top: 30%;
opacity: 1;
}
75% {
opacity: 1;
}
100% {
top: 100%;
opacity: 0;
}
}

@keyframes darma-loader-uiverse-prism-cross-scanner-move-v {
0% {
left: 0;
opacity: 0;
}
25% {
opacity: 1;
}
50% {
left: 45%;
opacity: 1;
}
75% {
opacity: 1;
}
100% {
left: 100%;
opacity: 0;
}
}

.darma-loader-uiverse-prism-cross-scanner__animation-effect-light {
animation: darma-loader-uiverse-prism-cross-scanner-effect 0.2s 0.1s infinite linear;
}
.darma-loader-uiverse-prism-cross-scanner__animation-effect-light-d {
animation: darma-loader-uiverse-prism-cross-scanner-effect 0.3s 0.2s infinite linear;
}
.darma-loader-uiverse-prism-cross-scanner__animation-effect-rot {
animation: darma-loader-uiverse-prism-cross-scanner-rot 0.8s infinite cubic-bezier(0.65, 0.05, 0.36, 1);
}
.darma-loader-uiverse-prism-cross-scanner__animation-effect-scale {
animation: darma-loader-uiverse-prism-cross-scanner-scale 0.8s infinite cubic-bezier(0.65, 0.05, 0.36, 1);
}

@keyframes darma-loader-uiverse-prism-cross-scanner-effect {
0% {
opacity: 0;
}
50% {
opacity: 1;
}
100% {
opacity: 0;
}
}

@keyframes darma-loader-uiverse-prism-cross-scanner-rot {
0% {
transform: rotate(0deg);
}
50% {
transform: rotate(180deg);
}
100% {
transform: rotate(360deg);
}
}

@keyframes darma-loader-uiverse-prism-cross-scanner-scale {
0% {
scale: 1;
}
50% {
scale: 1.9;
}
100% {
scale: 1;
}
}

.darma-loader-uiverse-prism-cross-scanner__e1 {
width: 1px;
height: 40px;
opacity: 0.3;
position: absolute;
top: 0;
left: 8%;
background-color: #0f9d58; /* Google Green */
}

.darma-loader-uiverse-prism-cross-scanner__e2 {
width: 60px;
height: 1px;
opacity: 0.8;
position: absolute;
top: 8%;
left: 0;
background-color: var(--loader-color, #4285f4); /* Google Blue */
}

.darma-loader-uiverse-prism-cross-scanner__e3 {
position: absolute;
top: 10%;
left: 12%;
font-family: "Segoe UI", Tahoma, Geneva, Verdana, sans-serif;
font-weight: 900;
font-size: 18px;
color: var(--loader-color, #4285f4); /* Google Blue */
}

.darma-loader-uiverse-prism-cross-scanner__e4 {
width: 1px;
height: 40px;
opacity: 0.3;
position: absolute;
top: 90%;
right: 10%;
background-color: #db4437; /* Google Red */
}

.darma-loader-uiverse-prism-cross-scanner__e5 {
width: 40px;
height: 1px;
opacity: 0.3;
position: absolute;
top: 100%;
right: 0;
background-color: var(--loader-secondary-color, #f4b400); /* Google Yellow */
}

.darma-loader-uiverse-prism-cross-scanner__e6 {
position: absolute;
top: 100%;
right: 0;
font-family: "Segoe UI", Tahoma, Geneva, Verdana, sans-serif;
font-size: 32px;
color: #0f9d58; /* Google Green */
}

.darma-loader-uiverse-prism-cross-scanner__e7 {
width: 1px;
height: 20px;
position: absolute;
bottom: 0;
left: 0;
transform: rotate(45deg);
animation: darma-loader-uiverse-prism-cross-scanner-height 1s infinite cubic-bezier(0.65, 0.05, 0.36, 1);
background-color: var(--loader-secondary-color, #f4b400); /* Google Yellow */
}

@keyframes darma-loader-uiverse-prism-cross-scanner-height {
0% {
bottom: 0%;
left: 0%;
height: 0px;
}
25% {
height: 90px;
}
50% {
bottom: 100%;
left: 100%;
height: 90px;
}
75% {
height: 0px;
}
100% {
bottom: 0%;
left: 0%;
height: 0px;
}
}

.darma-loader-uiverse-prism-cross-scanner__e8 {
width: 20px;
height: 1px;
position: absolute;
bottom: 50%;
left: 0;
animation: darma-loader-uiverse-prism-cross-scanner-width 1.5s infinite cubic-bezier(0.65, 0.05, 0.36, 1);
background-color: #0f9d58; /* Google Green */
}

@keyframes darma-loader-uiverse-prism-cross-scanner-width {
0% {
left: 0%;
width: 0px;
}
50% {
left: 100%;
width: 90px;
}
100% {
left: 0%;
width: 0px;
}
}

